/**
 * Validation helper module.
 * Each exported function returns an array of error strings (empty = valid).
 */

'use strict';

// ---------------------------------------------------------------------------
// Primitive validators
// ---------------------------------------------------------------------------

/**
 * Returns true when value is a finite integer (or a string that represents one).
 */
function isNumericId(value) {
  if (value === undefined || value === null) return false;
  // Allow numeric strings that arrive from URL params
  const n = Number(value);
  return Number.isFinite(n) && Math.floor(n) === n;
}

/**
 * Returns true when value is a non-null, non-array string (or can be treated
 * as one after strict type checking).
 */
function isString(value) {
  return typeof value === 'string';
}

/**
 * Loosely validates an e-mail address.
 * Enforces the structure local@domain with a TLD and rejects obvious junk.
 */
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
function isValidEmail(value) {
  return isString(value) && EMAIL_REGEX.test(value);
}

// ---------------------------------------------------------------------------
// Field-level validators (return an array of error messages)
// ---------------------------------------------------------------------------

/**
 * Validate an `id` coming from a URL parameter.
 * @param {*}      value  - raw value (usually a string from req.params)
 * @param {string} field  - field name used in error messages
 */
function validateId(value, field = 'id') {
  const errors = [];
  if (value === undefined || value === null || value === '') {
    errors.push(`"${field}" is required`);
  } else if (!isNumericId(value)) {
    errors.push(`"${field}" must be a numeric integer (received: ${JSON.stringify(value)})`);
  }
  return errors;
}

/**
 * Validate a `name` field from a request body.
 * Rules: required, string, 1–100 characters.
 * @param {*}      value
 * @param {string} field
 * @param {object} [opts]
 * @param {boolean} [opts.required=true]  - treat missing / undefined as an error
 */
function validateName(value, field = 'name', { required = true } = {}) {
  const errors = [];
  const missing = value === undefined || value === null;

  if (missing) {
    if (required) errors.push(`"${field}" is required`);
    return errors; // nothing else to check
  }

  if (!isString(value)) {
    errors.push(`"${field}" must be a string (received: ${typeof value})`);
    return errors;
  }

  const trimmed = value.trim();
  if (trimmed.length < 1) {
    errors.push(`"${field}" must be at least 1 character long`);
  } else if (trimmed.length > 100) {
    errors.push(`"${field}" must be at most 100 characters long (received: ${trimmed.length})`);
  }

  return errors;
}

/**
 * Validate an `email` field from a request body.
 * Rules: required, string, valid e-mail format, max 254 characters.
 * @param {*}      value
 * @param {string} field
 * @param {object} [opts]
 * @param {boolean} [opts.required=true]
 */
function validateEmail(value, field = 'email', { required = true } = {}) {
  const errors = [];
  const missing = value === undefined || value === null;

  if (missing) {
    if (required) errors.push(`"${field}" is required`);
    return errors;
  }

  if (!isString(value)) {
    errors.push(`"${field}" must be a string (received: ${typeof value})`);
    return errors;
  }

  if (!isValidEmail(value)) {
    errors.push(`"${field}" must be a valid email address (received: ${JSON.stringify(value)})`);
  }

  if (value.length > 254) {
    errors.push(`"${field}" must be at most 254 characters long (received: ${value.length})`);
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Composite request validators (return combined error arrays)
// ---------------------------------------------------------------------------

/**
 * Validate the :id URL parameter on routes like /users/:id.
 */
function validateUserIdParam(params) {
  return validateId(params && params.id, 'id');
}

/**
 * Validate the body for POST /users (all fields required).
 */
function validateCreateUserBody(body) {
  const errors = [
    ...validateName(body && body.name, 'name', { required: true }),
    ...validateEmail(body && body.email, 'email', { required: true }),
  ];
  return errors;
}

/**
 * Validate the body for PUT /users/:id (fields are optional; if provided they
 * must still pass type/length/format rules).
 */
function validateUpdateUserBody(body) {
  const errors = [
    ...validateName(body && body.name, 'name', { required: false }),
    ...validateEmail(body && body.email, 'email', { required: false }),
  ];
  return errors;
}

// ---------------------------------------------------------------------------
// Express middleware factory
// ---------------------------------------------------------------------------

/**
 * Returns an Express middleware that runs `validatorFn(req)`, collects the
 * returned error strings, and responds with a 400 if any errors are found.
 *
 * Usage:
 *   router.post('/users', validate(req => validateCreateUserBody(req.body)), handler);
 *
 * @param {function(import('express').Request): string[]} validatorFn
 */
function validate(validatorFn) {
  return (req, res, next) => {
    const errors = validatorFn(req);
    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    next();
  };
}

module.exports = {
  // Primitive helpers (exported for unit testing)
  isNumericId,
  isString,
  isValidEmail,
  // Field validators
  validateId,
  validateName,
  validateEmail,
  // Composite request validators
  validateUserIdParam,
  validateCreateUserBody,
  validateUpdateUserBody,
  // Middleware factory
  validate,
};

