 * Validate a user id sourced from a URL parameter.
 * Must be a whole-number string that converts to a finite positive integer.
 *
 * @param {string} raw - The raw string value from req.params.id
 * @returns {string[]} Array of error messages (empty = valid)
 */
function validateId(raw) {
  const errors = [];

  if (raw === undefined || raw === null || raw === '') {
    errors.push('id is required');
    return errors;
  }

  // Only allow strings that look like plain integers (no decimals, signs, etc.)
  if (!/^\d+$/.test(String(raw))) {
    errors.push('id must be a positive integer');
    return errors;
  }

  const num = Number(raw);
  if (!Number.isFinite(num) || num <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate the `name` field from a request body.
 *
 * @param {*} name - Value to validate
 * @returns {string[]} Array of error messages (empty = valid)
 */
function validateName(name) {
  const errors = [];

  if (name === undefined || name === null) {
    errors.push('name is required');
    return errors;
  }

  if (typeof name !== 'string') {
    errors.push('name must be a string');
    return errors;  // length checks are meaningless on non-strings
  }

  if (name.length < NAME_MIN) {
    errors.push(`name must be at least ${NAME_MIN} character`);
  }

  if (name.length > NAME_MAX) {
    errors.push(`name must be at most ${NAME_MAX} characters`);
  }

  return errors;
}

/**
 * Validate the `email` field from a request body.
 *
 * @param {*} email - Value to validate
 * @returns {string[]} Array of error messages (empty = valid)
 */
function validateEmail(email) {
  const errors = [];

  if (email === undefined || email === null) {
    errors.push('email is required');
    return errors;
  }

  if (typeof email !== 'string') {
    errors.push('email must be a string');
    return errors;
  }

  if (email.length > EMAIL_MAX) {
    errors.push(`email must be at most ${EMAIL_MAX} characters`);
  }

  if (!EMAIL_REGEX.test(email)) {
    errors.push('email must be a valid email address');
  }

  return errors;
}

/**
 * Validate all fields required to create a new user (name + email).
 *
 * @param {object} body - req.body
 * @returns {string[]} Combined error messages from all field validators
 */
function validateCreateUser(body) {
  const { name, email } = body || {};
  return [
    ...validateName(name),
    ...validateEmail(email),
  ];
}

/**
 * Validate all fields required to update an existing user (id + name + email).
 * The id is validated separately from the URL param; name and email are from
 * the request body.
 *
 * @param {string} rawId  - req.params.id (string from URL)
 * @param {object} body   - req.body
 * @returns {string[]} Combined error messages from all field validators
 */
function validateUpdateUser(rawId, body) {
  const { name, email } = body || {};
  return [
    ...validateId(rawId),
    ...validateName(name),
    ...validateEmail(email),
  ];
}

/**
 * Convenience: run validators and, if any errors exist, send a 400 response.
 * Returns true when a 400 was sent so the caller can `return` early.
 *
 * @param {string[]} errors - Collected error messages
 * @param {import('express').Response} res - Express response object
 * @returns {boolean} true if a 400 was sent, false otherwise
 */
function sendValidationError(errors, res) {
  if (errors.length === 0) return false;
  res.status(400).json({ error: 'Validation failed', details: errors });
  return true;
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
  sendValidationError,
};

