/**
 * validation.js — reusable input-validation helpers.
 *
 * Each validator returns an array of human-readable error strings.
 * An empty array means the value is valid.
 *
 * validateUserBody() aggregates field-level errors and is the primary
 * entry point for route handlers.
 */

const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a route/query parameter that must be a positive integer id.
 * Accepts the raw string value from req.params.
 *
 * @param {string} raw  - The string value to test (e.g. req.params.id)
 * @param {string} [field='id'] - Field label used in error messages
 * @returns {string[]} Array of error messages (empty = valid)
 */
function validateId(raw, field = 'id') {
  const errors = [];

  if (raw === undefined || raw === null || raw === '') {
    errors.push(`"${field}" is required`);
    return errors;
  }

  if (!/^\d+$/.test(String(raw))) {
    errors.push(`"${field}" must be a positive integer`);
    return errors;
  }

  const n = Number(raw);
  if (!Number.isInteger(n) || n < 1) {
    errors.push(`"${field}" must be a positive integer`);
  }

  return errors;
}

/**
 * Validate a "name" field.
 *
 * Rules:
 *  - Required (unless options.required is false)
 *  - Must be a string
 *  - Length: 1–100 characters
 *
 * @param {*}      value
 * @param {object} [options]
 * @param {boolean} [options.required=true]
 * @returns {string[]}
 */
function validateName(value, { required = true } = {}) {
  const errors = [];

  const missing = value === undefined || value === null || value === '';
  if (missing) {
    if (required) errors.push('"name" is required');
    return errors; // no further checks on an absent value
  }

  if (typeof value !== 'string') {
    errors.push('"name" must be a string');
    return errors;
  }

  const trimmed = value.trim();
  if (trimmed.length < 1) {
    errors.push('"name" must be at least 1 character long');
  } else if (trimmed.length > 100) {
    errors.push('"name" must be at most 100 characters long');
  }

  return errors;
}

/**
 * Validate an "email" field.
 *
 * Rules:
 *  - Required (unless options.required is false)
 *  - Must be a string
 *  - Must match a basic email format (local@domain.tld)
 *  - Maximum 254 characters (RFC 5321 limit)
 *
 * @param {*}      value
 * @param {object} [options]
 * @param {boolean} [options.required=true]
 * @returns {string[]}
 */
function validateEmail(value, { required = true } = {}) {
  const errors = [];

  const missing = value === undefined || value === null || value === '';
  if (missing) {
    if (required) errors.push('"email" is required');
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push('"email" must be a string');
    return errors;
  }

  if (value.length > 254) {
    errors.push('"email" must be at most 254 characters long');
  }

  if (!EMAIL_RE.test(value)) {
    errors.push('"email" must be a valid email address (e.g. user@example.com)');
  }

  return errors;
}

/**
 * Validate a user request body ({ name, email }).
 *
 * @param {object} body          - req.body
 * @param {object} [options]
 * @param {boolean} [options.requireName=true]  - Treat name as required
 * @param {boolean} [options.requireEmail=true] - Treat email as required
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateUserBody(body = {}, { requireName = true, requireEmail = true } = {}) {
  const errors = [
    ...validateName(body.name,   { required: requireName }),
    ...validateEmail(body.email, { required: requireEmail }),
  ];

  return { valid: errors.length === 0, errors };
}

module.exports = { validateId, validateName, validateEmail, validateUserBody };

