/**
 * Validate that `value` is a non-empty string within the given length bounds.
 *
 * @param {*}      value
 * @param {string} fieldName
 * @param {object} [opts]
 * @param {number} [opts.min=1]
 * @param {number} [opts.max=Infinity]
 * @returns {string[]} Validation error messages.
 */
function validateString(value, fieldName, { min = 1, max = Infinity } = {}) {
