  if (value === undefined || value === null) return errors; // presence checked elsewhere
  if (typeof value !== 'string') {
    errors.push(`"${fieldName}" must be a string`);
    return errors;
  }
  const len = value.length;
  if (len < min) {
    errors.push(`"${fieldName}" must be at least ${min} character${min !== 1 ? 's' : ''} long`);
  }
  if (len > max) {
    errors.push(`"${fieldName}" must not exceed ${max} characters`);
  }
