 * RFC 5321 maximum address length of 254 characters.
 *
 * @param {*}      value
 * @param {string} [fieldName='email']
 * @returns {string[]} Validation error messages.
 */
function validateEmail(value, fieldName = 'email') {
  const errors = [];
  if (value === undefined || value === null) return errors; // presence checked elsewhere
  if (typeof value !== 'string') {
    errors.push(`"${fieldName}" must be a string`);
    return errors;
  }
  if (value.length > 254) {
    errors.push(`"${fieldName}" must not exceed 254 characters`);
  }
  if (!EMAIL_REGEX.test(value)) {
    errors.push(`"${fieldName}" must be a valid email address`);
  }
