/**
 * validation.js
 * Reusable input-validation helpers for Express route handlers.
 *
 * Each validator returns an array of human-readable error strings.
 * An empty array means the input is valid.
 */

'use strict';

// ---------------------------------------------------------------------------
// Primitive validators
// ---------------------------------------------------------------------------

/**
 * Returns true when `value` is a finite number or a string that parses to one.
 */
function isNumeric(value) {
  if (value === null || value === undefined || value === '') return false;
  return !isNaN(Number(value)) && isFinite(value);
}

/**
 * Basic RFC-5321 / RFC-5322 email check.
 * Covers the vast majority of real-world addresses without being overly strict.
 */
const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
function isValidEmail(value) {
  return typeof value === 'string' && EMAIL_RE.test(value);
}

// ---------------------------------------------------------------------------
// Field-level validators
// ---------------------------------------------------------------------------

/**
 * Validate a route/query parameter that must be a numeric ID.
 *
 * @param {*}      value  - The raw value to check (e.g. req.params.id)
 * @param {string} label  - Field name used in error messages (default "id")
 * @returns {string[]}    - Array of error messages (empty = valid)
 */
function validateId(value, label = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`"${label}" is required`);
    return errors; // no point checking further
  }

  if (!isNumeric(value)) {
    errors.push(`"${label}" must be a numeric value`);
  }

  return errors;
}

/**
 * Validate a "name" field.
 *  - Required
 *  - Must be a string
 *  - Length: 1 – 100 characters
 *
 * @param {*}      value
 * @param {string} label  (default "name")
 * @returns {string[]}
 */
function validateName(value, label = 'name') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${label}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${label}" must be a string`);
    return errors;
  }

  const trimmed = value.trim();

  if (trimmed.length < 1) {
    errors.push(`"${label}" must not be empty`);
  } else if (trimmed.length > 100) {
    errors.push(`"${label}" must be 100 characters or fewer (received ${trimmed.length})`);
  }

  return errors;
}

/**
 * Validate an "email" field.
 *  - Required
 *  - Must be a string
 *  - Must match email format
 *  - Max 254 characters (RFC 5321 limit)
 *
 * @param {*}      value
 * @param {string} label  (default "email")
 * @returns {string[]}
 */
function validateEmail(value, label = 'email') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${label}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${label}" must be a string`);
    return errors;
  }

  if (value.length > 254) {
    errors.push(`"${label}" must be 254 characters or fewer (received ${value.length})`);
  }

  if (!isValidEmail(value)) {
    errors.push(`"${label}" must be a valid email address`);
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Composite validators
// ---------------------------------------------------------------------------

/**
 * Validate the body of a user create/update request.
 * Expects { name, email } in the body object.
 *
 * @param {object} body  - req.body
 * @returns {string[]}   - All accumulated errors across all fields
 */
function validateUserBody(body) {
  if (!body || typeof body !== 'object') {
    return ['Request body must be a JSON object'];
  }

  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

// ---------------------------------------------------------------------------
// Express middleware factory
// ---------------------------------------------------------------------------

/**
 * Returns an Express middleware that runs `validatorFn` and, if errors are
 * found, immediately responds with 400 + a descriptive payload.
 *
 * Usage:
 *   router.post('/users', validate(req => validateUserBody(req.body)), handler)
 *
 * @param {function(req): string[]} validatorFn
 * @returns {function} Express middleware
 */
function validate(validatorFn) {
  return (req, res, next) => {
    const errors = validatorFn(req);
    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    next();
  };
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  validate,
  validateId,
  validateName,
  validateEmail,
  validateUserBody,
  // Expose primitives for unit-testing
  isNumeric,
  isValidEmail,
};

