// Primitive validators
// ---------------------------------------------------------------------------

/**
 * Validates a route/query parameter that must be a whole-number ID.
 *
 * @param {string} raw   - The raw string value (e.g. req.params.id).
 * @param {string} field - Field label used in error messages.
 * @returns {string[]} Array of validation errors (empty = valid).
 */
function validateId(raw, field = 'id') {
  const errors = [];

  if (raw === undefined || raw === null || raw === '') {
    errors.push(`"${field}" is required`);
    return errors; // no point running further checks
  }

  const n = Number(raw);
  if (!Number.isInteger(n) || n <= 0) {
    errors.push(`"${field}" must be a positive integer`);
  }

  return errors;
}

/**
 * Validates a "name" string field.
 *
 * Rules: required, must be a non-empty string, length 1–100 characters.
 *
 * @param {*}      value   - Value from the request body.
 * @param {string} field   - Field label used in error messages.
 * @param {object} [opts]
 * @param {boolean} [opts.required=true] - Whether the field must be present.
 * @returns {string[]} Array of validation errors.
 */
function validateName(value, field = 'name', { required = true } = {}) {
  const errors = [];

  const missing = value === undefined || value === null || value === '';
  if (missing) {
    if (required) errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  const trimmed = value.trim();
  if (trimmed.length < 1) {
    errors.push(`"${field}" must not be empty or whitespace-only`);
  } else if (trimmed.length > 100) {
    errors.push(`"${field}" must be 100 characters or fewer (got ${trimmed.length})`);
  }

  return errors;
}

/**
 * Validates an email address field.
 *
 * Rules: required, must be a string, basic RFC-5321 format, max 254 characters.
 *
 * @param {*}      value - Value from the request body.
 * @param {string} field - Field label used in error messages.
 * @param {object} [opts]
 * @param {boolean} [opts.required=true] - Whether the field must be present.
 * @returns {string[]} Array of validation errors.
 */
function validateEmail(value, field = 'email', { required = true } = {}) {
  const errors = [];

  const missing = value === undefined || value === null || value === '';
  if (missing) {
    if (required) errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  if (value.length > 254) {
    errors.push(`"${field}" must be 254 characters or fewer (got ${value.length})`);
  }

  // Basic but practical email regex: local@domain.tld
  // Allows plus-addressing and common special chars in the local part.
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!EMAIL_RE.test(value)) {
    errors.push(`"${field}" must be a valid email address`);
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Composite validators (one per request shape)
// ---------------------------------------------------------------------------

/**
 * Validates the body of a POST /users request.
 * Both "name" and "email" are required.
 *
 * @param {object} body - req.body
 * @returns {string[]} Aggregated validation errors.
 */
function validateCreateUser(body) {
  return [
    ...validateName(body.name, 'name', { required: true }),
    ...validateEmail(body.email, 'email', { required: true }),
  ];
}

/**
 * Validates the body of a PUT /users/:id request.
 * At least one of "name" or "email" must be supplied; each is validated only
 * when present.
 *
 * @param {object} body - req.body
 * @returns {string[]} Aggregated validation errors.
 */
function validateUpdateUser(body) {
  const errors = [];

  const hasName  = body.name  !== undefined;
  const hasEmail = body.email !== undefined;

  if (!hasName && !hasEmail) {
    errors.push('At least one field ("name" or "email") must be provided for an update');
    return errors;
  }

  if (hasName)  errors.push(...validateName(body.name,   'name',  { required: true }));
  if (hasEmail) errors.push(...validateEmail(body.email, 'email', { required: true }));

  return errors;
}

