// Response helper
// ---------------------------------------------------------------------------

/**
 * Sends a standardised 400 response when validation fails.
 * Returns `true` if a response was sent (caller should return early),
 * `false` if validation passed.
 *
 * @param {string[]} errors - Array of validation error messages.
 * @param {object}   res    - Express response object.
 * @returns {boolean}
 */
function sendValidationError(errors, res) {
  if (errors.length === 0) return false;

  res.status(400).json({
    error:   'Validation failed',
    details: errors,
  });
  return true;
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
  sendValidationError,
};

