  }

  return errors;
}

/**
 * Validates a name field.
 *
 * Rules:
 *   - Required (non-empty after trimming)
 *   - Must be a string
 *   - Length: 1–100 characters
 *
 * @param {*} value
 * @param {string} field
 * @returns {string[]}
 */
function validateName(value, field = 'name') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  const trimmed = value.trim();

  if (trimmed.length === 0) {
    errors.push(`"${field}" must not be empty`);
  } else if (trimmed.length > 100) {
    errors.push(`"${field}" must be at most 100 characters (got ${trimmed.length})`);
  }

  return errors;
}

/**
 * Validates an email field.
 *
 * Rules:
 *   - Required
 *   - Must be a string
 *   - Must match basic email format
 *   - Length: max 254 characters (RFC 5321)
 *
 * @param {*} value
 * @param {string} field
 * @returns {string[]}
 */
function validateEmail(value, field = 'email') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  if (value.trim().length === 0) {
    errors.push(`"${field}" must not be empty`);
    return errors;
  }

  if (value.length > 254) {
    errors.push(`"${field}" must be at most 254 characters (got ${value.length})`);
  }

  if (!EMAIL_REGEX.test(value)) {
    errors.push(`"${field}" must be a valid email address`);
  }

  return errors;
}

/**
 * Validates the full user body (name + email).
 * Collect ALL errors so the caller gets a complete picture in one shot.
 *
 * @param {object} body
 * @returns {string[]}
 */
function validateUserBody(body) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

/**
 * Express middleware factory.
 * Runs the supplied validator against `req.body`, `req.params`, or `req.query`
 * and immediately returns a 400 with all errors when validation fails.
 *
 * @param {Function} validatorFn - A function that receives the target object
 *                                 and returns an array of error strings.
 * @param {'body'|'params'|'query'} source - Which part of the request to validate.
 * @returns {import('express').RequestHandler}
 */
function validate(validatorFn, source = 'body') {
  return (req, res, next) => {
    const errors = validatorFn(req[source]);
    if (errors.length > 0) {
      return res.status(400).json({ errors });
    }
    next();
  };
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateUserBody,
  validate,
};

