/**
 * Validation helper module.
 * Each exported function returns an array of error strings.
 * An empty array means all checks passed.
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user ID route/query parameter.
 * Accepts a raw string (from req.params / req.query) or a number (from req.body).
 *
 * @param {*}      value  - The raw value to check.
 * @param {string} field  - Field label used in error messages (default: "id").
 * @returns {string[]}    - Array of validation error messages.
 */
function validateId(value, field = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`"${field}" is required`);
    return errors; // no point running further checks
  }

  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0) {
    errors.push(`"${field}" must be a positive integer`);
  }

  return errors;
}

/**
 * Validate a user name value.
 *
 * @param {*}      value  - The raw value to check.
 * @param {string} field  - Field label used in error messages (default: "name").
 * @param {boolean} required - Whether the field is mandatory (default: true).
 * @returns {string[]}
 */
function validateName(value, field = 'name', required = true) {
  const errors = [];

  const missing = value === undefined || value === null || value === '';
  if (missing) {
    if (required) errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  const trimmed = value.trim();
  if (trimmed.length < 1) {
    errors.push(`"${field}" must be at least 1 character long`);
  }
  if (trimmed.length > 100) {
    errors.push(`"${field}" must not exceed 100 characters`);
  }

  return errors;
}

/**
 * Validate an e-mail address value.
 *
 * @param {*}      value    - The raw value to check.
 * @param {string} field    - Field label used in error messages (default: "email").
 * @param {boolean} required - Whether the field is mandatory (default: true).
 * @returns {string[]}
 */
function validateEmail(value, field = 'email', required = true) {
  const errors = [];

  const missing = value === undefined || value === null || value === '';
  if (missing) {
    if (required) errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  if (!EMAIL_REGEX.test(value)) {
    errors.push(`"${field}" must be a valid email address`);
  }

  if (value.length > 254) {
    errors.push(`"${field}" must not exceed 254 characters`);
  }

  return errors;
}

/**
 * Validate a complete user body (name + email).
 * Used by POST (all fields required) and PUT (all fields required for full update).
 *
 * @param {object} body
 * @returns {string[]}
 */
function validateUserBody(body) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

/**
 * Validate a partial user body (name and/or email).
 * Used by PATCH where at least one field must be present but neither is individually required.
 *
 * @param {object} body
 * @returns {string[]}
 */
function validatePartialUserBody(body) {
  const errors = [];

  const hasName  = body.name  !== undefined;
  const hasEmail = body.email !== undefined;

  if (!hasName && !hasEmail) {
    errors.push('At least one of "name" or "email" must be provided');
    return errors;
  }

  if (hasName)  errors.push(...validateName(body.name,   'name',  false));
  if (hasEmail) errors.push(...validateEmail(body.email, 'email', false));

  return errors;
}

/**
 * Express middleware factory — runs the supplied validator function and
 * immediately responds with 400 if any errors are found.
 *
 * Usage:
 *   router.post('/users', validate(req => validateUserBody(req.body)), handler)
 *
 * @param {function(req): string[]} validatorFn
 * @returns {function} Express middleware
 */
function validate(validatorFn) {
  return (req, res, next) => {
    const errors = validatorFn(req);
    if (errors.length > 0) {
      return res.status(400).json({ errors });
    }
    next();
  };
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateUserBody,
  validatePartialUserBody,
  validate,
};
